// Handler: you perform the request and return the response.
let response = sendWithRetry(request, { retries: 3, delay: 1000 });
return response;

const response = send(request);
// patch parses the body, edits every match, and re-serializes for you.
patch(response, 'items[*].price', 0);
return response;

// delay() — handler phase only.
delay(2000);
if (randomInt(1, 100) <= 10) return httpError(500, 'flaky upstream');
return send(request);

// Handler: the first 3 matching requests fail, then traffic passes through.
// counter() is in-memory — restart the app (or resetCounter) to start over.
var attempt = counter('flaky-start');
if (attempt <= 3) {
  return httpError(503, 'warming up, attempt ' + attempt);
}
return send(request);

// Request phase: mock a paginated list driven by the ?page= query param.
var page = Number(queryParam(request, 'page') || 1);
var perPage = 20;
json({
  page: page,
  items: fakeList(perPage, function (i) {
    var id = (page - 1) * perPage + i + 1;
    return { id: id, name: fakeName(), description: lorem(8) };
  }),
  hasMore: page < 5
});

// Request phase: inspect the JWT and warn when it is about to expire.
var auth = header(request, 'authorization');
if (auth) {
  var jwt = jwtDecode(auth);
  var expMs = (jwt.payload.exp || 0) * 1000;
  if (expMs && expMs - Date.now() < 60000) {
    notify('JWT expires in <60s (sub: ' + jwt.payload.sub + ')', { title: 'Auth' });
  }
}

// Response phase: replace the session cookie the server sets.
if (response) {
  setCookie(response, 'session', 'test-session', { path: '/', httpOnly: true, sameSite: 'Lax' });
}

// Handler: 10% of matching traffic gets the mocked B-variant.
if (randomBool(0.1)) {
  return json({ variant: 'B', mocked: true });
}
return send(request);

// Response phase: save the fresh token into a variable after login.
// Use it in a request rule on other endpoints: bearer(getVariable('token'))
if (response) {
  var token = pickOne(response, 'data.accessToken');
  if (token !== null) setVariable('token', token);
}

// Request phase: a realistic user list without touching the backend.
json({
  users: fakeList(10, function (i) {
    return { id: i + 1, name: fakeName(), email: fakeEmail(), phone: fakePhone(), bio: lorem(12) };
  })
});
